import { type CSSProperties, type PropsWithChildren } from 'react';

import { container } from './InnerContainer.sty.js';
import { Flex } from '../../../../../../layouts/flex/Flex.js';
import type { InnerWrapperProps } from '../../../../types/internal/pie-chart.js';

interface InnerContainerProps
  extends Pick<InnerWrapperProps, 'width' | 'height'> {
  donutInner: number;
}

export const InnerContainer = ({
  donutInner,
  height,
  width,
  children,
}: PropsWithChildren<InnerContainerProps>) => {
  const containerStyle: CSSProperties = {
    top: `${height / 2 - donutInner / 2}px`,
    left: `${width / 2 - donutInner / 2}px`,
  };

  return (
    <Flex
      justifyContent="center"
      alignItems="center"
      style={containerStyle}
      className={container}
    >
      {children}
    </Flex>
  );
};
